# Create a CloudFront cache policy with a long TTL for static assets
# Used by both PoPs and RECs
POLICY_ID=$(aws cloudfront create-cache-policy \
  --cache-policy-config '{
    "Name": "static-assets-365d",
    "Comment": "Long TTL for versioned static assets",
    "DefaultTTL": 31536000,
    "MaxTTL": 31536000,
    "MinTTL": 0,
    "ParametersInCacheKeyAndForwardedToOrigin": {
      "EnableAcceptEncodingGzip": true,
      "EnableAcceptEncodingBrotli": true,
      "HeadersConfig": {"HeaderBehavior": "none"},
      "CookiesConfig": {"CookieBehavior": "none"},
      "QueryStringsConfig": {"QueryStringBehavior": "none"}
    }
  }' --query 'CachePolicy.Id' --output text)

echo "Static cache policy: $POLICY_ID"

# Separate no-cache policy for dynamic API responses (bypasses both PoP and REC)
NO_CACHE=$(aws cloudfront create-cache-policy \
  --cache-policy-config '{
    "Name": "no-cache-api",
    "Comment": "Disable caching for API endpoints",
    "DefaultTTL": 0, "MaxTTL": 0, "MinTTL": 0,
    "ParametersInCacheKeyAndForwardedToOrigin": {
      "EnableAcceptEncodingGzip": false,
      "EnableAcceptEncodingBrotli": false,
      "HeadersConfig": {"HeaderBehavior": "none"},
      "CookiesConfig": {"CookieBehavior": "none"},
      "QueryStringsConfig": {"QueryStringBehavior": "none"}
    }
  }' --query 'CachePolicy.Id' --output text)

echo "No-cache policy: $NO_CACHE

# Create a cache policy that strips UTM tracking params from the cache key
# /image.jpg?utm_source=email and /image.jpg?utm_campaign=promo
# will both hit the same cached object
aws cloudfront create-cache-policy \
  --cache-policy-config '{
    "Name": "strip-utm-params",
    "DefaultTTL": 86400,
    "MaxTTL": 31536000,
    "MinTTL": 0,
    "ParametersInCacheKeyAndForwardedToOrigin": {
      "EnableAcceptEncodingGzip": true,
      "EnableAcceptEncodingBrotli": true,
      "HeadersConfig": {"HeaderBehavior": "none"},
      "CookiesConfig": {"CookieBehavior": "none"},
      "QueryStringsConfig": {
        "QueryStringBehavior": "whitelist",
        "QueryStrings": {
          "Quantity": 2,
          "Items": ["w", "h"]
        }
      }
    }
  }' --query 'CachePolicy.Id' --output text
# Only the ?w= and ?h= (width/height for image resize) params are in the cache key
# All other query params (UTM, session, etc.) are stripped from the key but NOT forwarded to origin

# Create a no-cache policy for dynamic API paths
aws cloudfront create-cache-policy --cache-policy-config '{
  "Name": "NoCachePolicy",
  "DefaultTTL": 0,
  "MaxTTL": 0,
  "MinTTL": 0,
  "ParametersInCacheKeyAndForwardedToOrigin": {
    "EnableAcceptEncodingGzip": false,
    "EnableAcceptEncodingBrotli": false,
    "HeadersConfig": {"HeaderBehavior": "none"},
    "CookiesConfig": {"CookieBehavior": "none"},
    "QueryStringsConfig": {"QueryStringBehavior": "none"}
  }
}'

resource "aws_cloudfront_distribution" "main" {
  enabled             = true
  default_root_object = "index.html"

  origin {
    domain_name = aws_s3_bucket.assets.bucket_regional_domain_name
    origin_id   = "s3-assets"

    # Enable Origin Shield in the region closest to your S3 bucket
    origin_shield {
      enabled              = true
      origin_shield_region = "us-east-1"
    }
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "s3-assets"
    viewer_protocol_policy = "redirect-to-https"

    # Reference a managed cache policy (CachingOptimized)
    cache_policy_id = data.aws_cloudfront_cache_policy.optimized.id
  }

  # Cache behavior for API paths — bypass cache entirely
  ordered_cache_behavior {
    path_pattern           = "/api/*"
    allowed_methods        = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "s3-assets"
    viewer_protocol_policy = "https-only"
    cache_policy_id        = data.aws_cloudfront_cache_policy.no_cache.id
  }

  restrictions {
    geo_restriction { restriction_type = "none" }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

data "aws_cloudfront_cache_policy" "optimized" {
  name = "Managed-CachingOptimized"
}

data "aws_cloudfront_cache_policy" "no_cache" {
  name = "Managed-CachingDisabled"
}
